import os
from pathlib import Path

def delete_uploaded_file(filename: str, uploads_dir: str = 'uploads') -> bool:
    """
    Delete a file from the uploads directory.

    Args:
        filename: The name of the file to delete.
        uploads_dir: Base uploads directory.

    Returns:
        True if the file was deleted, False if it did not exist or an error occurred.
    """
    safe_name = os.path.basename(filename)        # Prevent path traversal
    file_path = Path(uploads_dir) / safe_name

    try:
        file_path.unlink()
        return True
    except FileNotFoundError:
        return False
    except Exception:
        return False